const input = $input.first().json;
const { token, offers, marketplace_url, api_key } = input.body || input;

// Validate required fields
if (!token) {
  return [{ json: { error: true, code: 'MISSING_TOKEN', message: 'Token is required' } }];
}
if (!offers || !Array.isArray(offers) || offers.length === 0) {
  return [{ json: { error: true, code: 'INVALID_OFFERS', message: 'Offers array is required and must not be empty' } }];
}
if (offers.length > 10000) {
  return [{ json: { error: true, code: 'TOO_MANY_OFFERS', message: 'Maximum 10000 offers per upload' } }];
}

// Decode JWT to extract vendor_id
try {
  const parts = token.split('.');
  if (parts.length !== 3) throw new Error('Invalid token format');
  const payload = JSON.parse(Buffer.from(parts[1], 'base64url').toString());

  if (payload.exp && payload.exp < Math.floor(Date.now() / 1000)) {
    return [{ json: { error: true, code: 'TOKEN_EXPIRED', message: 'Token has expired' } }];
  }

  const vendor_id = payload.sub || payload.vendor_id || payload.user_id;
  if (!vendor_id) {
    return [{ json: { error: true, code: 'INVALID_TOKEN', message: 'Token missing subject' } }];
  }

  return [{ json: {
    error: false,
    vendor_id,
    offers,
    marketplace_url: marketplace_url || null,
    api_key: api_key || null
  } }];
} catch (e) {
  return [{ json: { error: true, code: 'AUTH_FAILED', message: 'Token verification failed: ' + e.message } }];
}

const input = $input.first().json;
const offers = input.offers;

// Validate offer fields
const errors = [];
offers.forEach((o, i) => {
  if (!o.shop_sku) errors.push(`Offer ${i}: missing shop_sku`);
  if (o.price === undefined || o.price === null) errors.push(`Offer ${i}: missing price`);
  if (o.price !== undefined && (isNaN(Number(o.price)) || Number(o.price) < 0)) {
    errors.push(`Offer ${i}: invalid price '${o.price}'`);
  }
  if (o.quantity !== undefined && (isNaN(Number(o.quantity)) || Number(o.quantity) < 0)) {
    errors.push(`Offer ${i}: invalid quantity '${o.quantity}'`);
  }
});

if (errors.length > 0) {
  return [{ json: { error: true, code: 'VALIDATION_ERROR', message: errors.slice(0, 20).join('; ') + (errors.length > 20 ? ` ...and ${errors.length - 20} more` : ''), vendor_id: input.vendor_id, marketplace_url: input.marketplace_url, api_key: input.api_key } }];
}

// Build CSV for Mirakl Offers Import (OF01)
// Required columns: sku;product-id;product-id-type;price;quantity;state;logistic-class;...
const csvSeparator = ';';

// Map internal fields to Mirakl offer fields
const fieldMap = {
  'shop_sku': 'sku',
  'ean': 'product-id',
  'ean_type': 'product-id-type',
  'price': 'price',
  'original_price': 'price-original',
  'discount_price': 'discount-price',
  'quantity': 'quantity',
  'state': 'state-code',
  'logistic_class': 'logistic-class',
  'min_shipping_price': 'min-shipping-price',
  'min_shipping_price_additional': 'min-shipping-price-additional',
  'leadtime_to_ship': 'leadtime-to-ship',
  'description': 'description',
  'internal_description': 'internal-description',
  'available_start_date': 'available-start-date',
  'available_end_date': 'available-end-date',
  'discount_start_date': 'discount-start-date',
  'discount_end_date': 'discount-end-date',
  'min_quantity_alert': 'min-quantity-alert',
  'favorite_rank': 'favorite-rank',
  'allow_quote_requests': 'allow-quote-requests',
  'price_additional_info': 'price-additional-info',
  'min_order_quantity': 'min-order-quantity',
  'max_order_quantity': 'max-order-quantity',
  'package_quantity': 'package-quantity'
};

// Determine which columns we actually need based on data
const usedInternal = new Set();
offers.forEach(o => {
  Object.keys(o).forEach(k => {
    if (fieldMap[k]) usedInternal.add(k);
  });
});
// Always include core fields
['shop_sku', 'price', 'quantity', 'state'].forEach(k => usedInternal.add(k));

const orderedInternal = [...usedInternal];
const headers = orderedInternal.map(k => fieldMap[k]);

const escapeCSV = (val) => {
  let s = String(val === undefined || val === null ? '' : val);
  s = s.replace(/"/g, '""');
  if (s.includes(csvSeparator) || s.includes('"') || s.includes('\n')) {
    s = '"' + s + '"';
  }
  return s;
};

const headerLine = headers.join(csvSeparator);
const dataLines = offers.map(o => {
  return orderedInternal.map(k => {
    let val = o[k];
    // Default state to '11' (new) if not provided
    if (k === 'state' && (val === undefined || val === null || val === '')) val = '11';
    // Default quantity to 0 if not provided
    if (k === 'quantity' && (val === undefined || val === null)) val = 0;
    return escapeCSV(val);
  }).join(csvSeparator);
});

const csvContent = headerLine + '\n' + dataLines.join('\n');

return [{ json: {
  error: false,
  csv_content: csvContent,
  offer_count: offers.length,
  vendor_id: input.vendor_id,
  marketplace_url: input.marketplace_url,
  api_key: input.api_key
} }];

const input = $input.first().json;
const prevData = $('Build Offer CSV').first().json;

const statusCode = input.statusCode || input.status;
const mirakl_success = statusCode >= 200 && statusCode < 300;
const import_id = mirakl_success ? (input.body?.import_id || input.data?.import_id || input.import_id || null) : null;

return [{ json: {
  mirakl_success,
  import_id,
  status_code: statusCode,
  error_message: !mirakl_success ? (input.body?.message || input.message || 'Mirakl API error') : null,
  vendor_id: prevData.vendor_id,
  offer_count: prevData.offer_count,
  marketplace_url: prevData.marketplace_url
} }];

const mirakl = $('Parse Mirakl Response').first().json;
const syncLogResponse = $input.first().json;

const sync_log_id = Array.isArray(syncLogResponse) ? syncLogResponse[0]?.id : (syncLogResponse.id || syncLogResponse[0]?.id || null);

if (mirakl.mirakl_success) {
  return [{ json: {
    success: true,
    import_id: mirakl.import_id,
    sync_log_id,
    offer_count: mirakl.offer_count,
    message: `${mirakl.offer_count} offers submitted to Mirakl for import`
  } }];
} else {
  return [{ json: {
    success: false,
    error: 'mirakl_upload_failed',
    message: mirakl.error_message || 'Failed to upload offers to Mirakl',
    status_code: mirakl.status_code,
    sync_log_id
  } }];
}
